/*==============================================================*/
/* Table: CATCAT_CLI                                            */
/*==============================================================*/
CREATE TABLE CATCAT_CLI
(
    ID_CATCAT_CLI_CODE   INT NOT NULL AUTO_INCREMENT,
    CATCAT_CLI_NAME      VARCHAR(32) NOT NULL,
    CATCAT_CLI_VALID_FROM TIMESTAMP,
    CATCAT_CLI_VALID_TO  TIMESTAMP NULL,
    CATCAT_CLI_CREATED_BY VARCHAR(16),
    CATCAT_CLI_UPDATED_BY VARCHAR(16),
    CATCAT_CLI_CREATED_AT TIMESTAMP,
    CATCAT_CLI_UPDATED_AT TIMESTAMP,
    PRIMARY KEY (ID_CATCAT_CLI_CODE)
);

ALTER TABLE CATCAT_CLI COMMENT 'CATEGORIA CLIENTE';

/*==============================================================*/
/* Table: CATCLI                                                */
/*==============================================================*/
CREATE TABLE CATCLI
(
    ID_CATCLI_CODE       INT NOT NULL AUTO_INCREMENT,
    XID_CATCAT_CLI_CODE  INT,
    CATCLI_CODE          VARCHAR(16) NOT NULL,
    CATCLI_NAME          VARCHAR(64) NOT NULL,
    CATCLI_IMAGE_URL     VARCHAR(128),
    CATCLI_IMAGE_NAME    VARCHAR(128),
    CATCLI_VALID_FROM    TIMESTAMP,
    CATCLI_VALID_TO      TIMESTAMP NULL,
    CATCLI_CREATED_BY    VARCHAR(16),
    CATCLI_UPDATED_BY    VARCHAR(16),
    CATCLI_CREATED_AT    TIMESTAMP,
    CATCLI_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CATCLI_CODE)
);

ALTER TABLE CATCLI COMMENT 'CLIENTE';

/*==============================================================*/
/* Index: CAICLI_CODE                                           */
/*==============================================================*/
CREATE UNIQUE INDEX CAICLI_CODE ON CATCLI(CATCLI_CODE);

ALTER TABLE CATCLI ADD CONSTRAINT XID_CATCLI_CODE_XID_CATCAT_CLI_CODE FOREIGN KEY (XID_CATCAT_CLI_CODE)
    REFERENCES CATCAT_CLI (ID_CATCAT_CLI_CODE) ON DELETE RESTRICT;

